320→static inline bool PointInsideColl(CollData* cd, Vec3* point, float offset)
321→{
322→    f32 top, bottom;
323→    f32 left, right;
324→    f32 width, height;
325→    f32 topn;
326→    f32 x, y;
327→    f32 comp;
328→
329→    top = cd->ecb.top.y;
330→    bottom = cd->ecb.bottom.y;
331→    topn = cd->cur_pos.y;
332→    height = top - bottom;
333→    comp = 0.5f * height + offset;
334→    y = 0.5f * (top + bottom) + topn - point->y;
335→    if (ABS(y) > comp) {
336→        return false;
337→    }
338→
339→    right = cd->ecb.right.x;
340→    left = cd->ecb.left.x;
341→    topn = cd->cur_pos.x;
342→    width = right - left;
343→    comp = 0.5f * width + offset;
344→    x = 0.5f * (left + right) + topn - point->x;
345→    if (ABS(x) > comp) {
346→        return false;
347→    }
348→
349→    return true;
350→}
